  <Flex direction="column" gap="4">
    <Box style={{ maxWidth: "600px" }}>
      A custom card built with Box. Use Box with an explicit bg prop to create a
      card-like container that participates in the bg system as a provider.
    </Box>
    <Box bg="neutral" p="4" style={{ borderRadius: "8px", width: "300px" }}>
      <Button variant="secondary">Button (on neutral-1)</Button>
    </Box>
    <Card style={{ width: "300px" }}>
      <CardHeader>Header</CardHeader>
      <CardBody>Body</CardBody>
      <CardFooter>Footer</CardFooter>
    </Card>
  </Flex>
